const express = require('express');
const mongoose = require('mongoose');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/test', { useNewUrlParser: true, useUnifiedTopology: true });

// Define a schema and model for the example collection
const Schema = mongoose.Schema;
const ExampleSchema = new Schema({
  name: String,
  age: Number,
  password: String
});
const Example = mongoose.model('Example', ExampleSchema);

// Query builder function
function queryBuilder(filter, projection, sort) {
  const query = {};
  Object.keys(filter).forEach(key => {
    if (filter[key] && filter[key].$where) {
      query[key] = eval(filter[key].$where);
    } else if (filter[key]) {
      query[key] = filter[key];
    }
  });

  const projectionKeys = Object.keys(projection);
  const project = {};
  projectionKeys.forEach(key => {
    if (projection[key] !== 0) {
      project[key] = projection[key];
    }
  });

  const options = {};
  if (sort) {
    Object.keys(sort).forEach(key => {
      options['sort'] = { [key]: sort[key] };
    });
  }

  return Example.find(query, project, options);
}

// API endpoint for querying the database
const app = express();
app.get('/api/examples', async (req, res) => {
  const filter = req.query;
  const projection = {};
  if (req.query.projection) {
    Object.keys(req.query.projection).forEach(key => {
      projection[key] = req.query.projection[key];
    });
  }
  const sort = req.query.sort;
  try {
    const result = await queryBuilder(filter, projection, sort);
    res.json(result);
  } catch (err) {
    console.error(err);
    res.status(500).send('Internal Server Error');
  }
});

app.listen(3000, () => console.log('Server started on port 3000'));